import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NUMBERS = {
    "19": {
        "1": "<p>The red heifer law (vv1-22) opens with the double address to Moses and Aaron. This address pattern (rather than Moses alone) appears when Aaron and his sons have a specific implementing role — here Eleazar performs the ritual (v3). The chapter follows the Korah crisis (ch16-18) and the institutional reaffirmation of Aaronic priesthood (ch17-18), providing the purification mechanism for the mass death that preceded it.</p>",
        "2": "<p><em>Zōʾt ḥuqqat hattôrâ</em> — this is the statute of the instruction. The opening designation marks the red heifer law as a <strong>ḥuqqâ</strong> — a binding divine ordinance without stated rationale, as distinguished from <strong>mišpāṭ</strong> (judgment derived from principles) or <strong>ʿēḏût</strong> (testimony). The Mishnah (Parah 4:4) reports that King Solomon said he could understand all the Torah's laws but was unable to comprehend the red heifer's logic. The rabbis classified it as the archetype of laws that must be obeyed despite their apparent irrationality — perhaps precisely to test the nature of covenantal obedience.</p>",
        "3": "<p>The heifer is taken to Eleazar rather than Aaron himself — the high priest could not risk corpse-impurity (Lev 21:11), so his son performs the slaughter outside the camp. The location outside the camp mirrors the placement of the impurity-bearers in Num 5:2-4 and the sin offering of Lev 16:27; everything associated with impurity removal operates outside the sacred perimeter. This structural parallelism marks the red heifer as the primary mechanism for the most severe category of ritual impurity.</p>",
        "4": "<p>Eleazar sprinkles the blood seven times toward the front of the tent of meeting (<em>nōkaḥ pənê ʾōhel môʿēd</em>). Seven sprinklings appear in the most significant purification rites: the Day of Atonement (Lev 16:14), the skin-disease cleansing (Lev 14:7), and the tabernacle consecration (Exod 29:35-37). The direction of sprinkling — toward the sanctuary — symbolically connects the purification rite to the divine presence even though the animal dies outside the camp.</p>",
        "5": "<p>The entire heifer is burned — hide, flesh, blood, and dung. The totality of the burning distinguishes this from normal burnt offerings, where certain parts were disposed of separately (Lev 1:16; 4:11-12). Even the blood, which would normally be used on the altar or poured at its base, is incinerated here. The burning of the blood with the body is a unique feature that contributes to the law's paradoxical character: normally blood purifies (Lev 17:11), here it is eliminated with everything else to produce purifying ashes.</p>",
        "6": "<p>Cedar wood, hyssop, and scarlet yarn are added to the fire — the same three components used in the skin-disease purification rite (Lev 14:4,6,49-51) and, in a different form, the Passover ceremony (hyssop for blood application, Exod 12:22). This material triad consistently marks liminal purification contexts involving life, death, and restoration. Cedar connotes fragrance and permanence; hyssop connotes humility and cleansing; scarlet connotes life-blood and consecration.</p>",
        "7": "<p>The priest who performs the burning must wash his clothes and bathe, and is unclean until evening. The paradox of the red heifer law appears here for the first time: the officiating priest who produces the purifying substance is himself made impure by the process. This self-contamination extends through vv8 (the one who burned the heifer), v10 (the one who gathers the ashes), and v19,21 (the one who sprinkles the purifying water). The purifier is defiled by purifying; this structural inversion distinguishes the red heifer from every other purification rite.</p>",
        "8": "<p>The man who burned the heifer — distinct from Eleazar who slaughtered and sprinkled — also incurs evening-impurity. The spreading of impurity to multiple participants who never directly touched the corpse illustrates that the heifer bears a substitute corpse-impurity: it was killed outside the camp, burned like a sin offering, and transmits its acquired impurity to those who handle it.</p>",
        "9": "<p>A clean man gathers the ashes and deposits them in a clean place outside the camp (<em>miḥûṣ lammaḥăneh bəmāqôm ṭāhôr</em>). The ashes are permanently available as a standing resource for purification — the Mishnah (Parah 3) describes how the ashes from one red heifer could last for generations, with each successive heifer's ashes mixed with the previous. The ashes in storage are themselves clean (v9) even though gathering them makes the gatherer unclean (v10).</p>",
        "10": "<p>The ashes-gatherer is also unclean until evening. The permanent statute (<em>ḥuqqat ʿôlām</em>) that follows applies to both Israelites and resident aliens — the red heifer law, like many purity laws, covers all who live within the covenant community's perimeter regardless of ethnic origin. The universality reflects the understanding that corpse-impurity is a threat to the divine dwelling in the camp regardless of the affected person's identity.</p>",
        "11": "<p>The core corpse-impurity law: anyone who touches a human corpse (<em>kol-hannōgēaʿ bəmet nep̄eš kol-ʾāḏām</em> — touching the dead soul of any human) is unclean for seven days. The seven-day period is the most extended impurity duration in the Levitical system (for comparison, skin-disease purification runs up to seven days per stage, but some discharges are one day). The death-impurity's severity mirrors the theological weight of mortality itself: death is the ultimate violation of the holiness of life that YHWH embodies.</p>",
        "12": "<p>Purification requires the water of impurity (<em>mê hanniddâ</em>) on the third and seventh days. The third day may echo the three-day consecration periods throughout the Torah (Exod 19:11,15,16; Num 31:19); the seventh day marks completion (the creation week, the week of Levitical ordination, Lev 8:33-35). Failure to purify on both days means the uncleanness continues into a new seven-day cycle, not that it is cleared at the end of the first.</p>",
        "13": "<p>Deliberate failure to purify after corpse contact defiles the tabernacle (<em>ʾet-miškān YHWH ṭimmēʾ</em>) and brings the <em>kārēt</em> penalty — being cut off. The chain of defilement runs from person to tabernacle: the impure individual who ignores purification and enters the camp introduces corpse-impurity into the sacred sphere where YHWH dwells. The severity of the penalty reflects the magnitude of the pollution: the divine dwelling itself is implicated.</p>",
        "14": "<p>The tent-death law: when someone dies in a tent (<em>ʾōhel</em>), everything and everyone inside the tent, plus anyone who enters during the seven days, becomes unclean. The tent-space itself transmits corpse-impurity as an enclosed container; any person who enters the contaminated space becomes contaminated regardless of whether they touched the body. This spatial transmission principle is unique to corpse-impurity; other major impurities spread through direct contact, not through enclosed space.</p>",
        "15": "<p>Open containers (<em>kol-kelî p̄atûaḥ</em>) in the tent become unclean; containers with sealed lids (<em>ṣāmîḏ p̄āṯîl</em>) are protected. The distinction between sealed and open vessels reflects a practical and symbolic principle: the container that excludes outside impurity is protected from it. The Mishnah extensively develops this principle in tractate Ohalot (Tents), which catalogues the spatial and container transmission rules of corpse-impurity across 18 chapters.</p>",
        "16": "<p>Corpse-impurity in the open field — through a killed person, a natural death, a bone, or a grave — transmits seven-day impurity. The inclusion of bones and graves (not just whole corpses) extends the law to all human remains. Grave sites could not be left unmarked in Israel precisely because accidental contact would contaminate individuals, particularly Nazirites and priests. The Mishnah describes whitewashing graves before Passover to warn pilgrims (Matt 23:27 picks up this practice in its metaphorical critique).</p>",
        "17": "<p>The purification procedure: ashes of the burnt heifer are placed in a vessel and living/fresh water (<em>mayim ḥayyîm</em> — running water from a spring or stream, not standing water) is added. The combination of ash-water with living water creates the <em>mê niddâ</em> — the water of impurity/purification. The term <em>niddâ</em> normally refers to menstrual impurity (Lev 15:19-24), suggesting a conceptual link between the two categories of severe bodily impurity that require special ritual attention.</p>",
        "18": "<p>A clean person uses hyssop to sprinkle the purification water on the tent, vessels, and persons affected. Hyssop (<em>ʾēzôb</em>) is the standard application tool for purification liquids throughout the Torah (Exod 12:22; Lev 14:4,6,49,51-52; Ps 51:7). The plant's porous, brush-like structure makes it practically suited for sprinkling. The clean-person performing the sprinkling will become unclean (v19) — another iteration of the purifier-contaminated-by-purifying paradox.</p>",
        "19": "<p>The clean person sprinkles the unclean person on the third and seventh days — the same two-stage timeline as the general corpse-impurity rule in v12. On the seventh day the unclean person washes clothes and bathes, and is then clean by evening. The precise sequencing — third day sprinkling, seventh day sprinkling plus bathing — creates a two-stage ritual rather than a single ceremony, mirroring the seven-plus-eight-day structure of many Levitical purification rites.</p>",
        "20": "<p>Failure to purify brings the <em>kārēt</em> penalty (as in v13). The reason given: <em>miqdaš YHWH ṭimmēʾ</em> — the sanctuary of YHWH is defiled. This second statement of the defilement-of-sanctuary consequence reinforces that the entire purification system exists to protect the divine dwelling's holiness. The covenant community's integrity — YHWH able to dwell in the camp — depends on the proper management of impurity, making these seemingly technical laws matters of cosmic theology.</p>",
        "21": "<p>The permanent statute: the sprinkler of purification water must wash his clothes; touching the water makes one unclean until evening. The consistent impurity-of-the-purifier principle culminates here in a generalization covering anyone involved in the water. The law does not explain this paradox; its consistent structural feature across all the participants (v7,8,10,19,21) suggests it is an intentional design element rather than a byproduct. Post-biblical interpreters read it as a humility device: no purification agent should consider themselves above the impurity they address.</p>",
        "22": "<p>Closing principle: the unclean person who touches anything spreads uncleanness to that thing and anyone who then touches it. The secondary transmission rule makes the unclean person a radiating center of impurity, which is why strict separation from the camp was required during severe impurity periods. The chapter's final verse — transmission without limit until the seven-day cycle is completed — explains the urgency of proper purification before camp re-entry.</p>"
    },
    "20": {
        "1": "<p>The narrative jumps to the fortieth year of the wilderness period (cf. v28: Aaron dies in the fortieth year, Num 33:38). The community arrives at Kadesh in the Desert of Zin — the same Kadesh from which the spies were sent (Num 13:26) and where the sentence of forty years was pronounced (Num 14). The death of Miriam here marks the end of the founding generation. She receives only the terse notice that she died and was buried there — no details, no mourning notice like Aaron's (v29) and Moses's (Deut 34:8).</p>",
        "2": "<p>The water crisis parallels Exodus 17:1-7 at Rephidim. The shared features — no water, the community's assembly against Moses, Moses's staff, water from the rock — have led many scholars to identify these as parallel accounts of the same event (doublets in the Pentateuch's compositional history) or as two genuinely distinct events at different stages of the wilderness. The Deuteronomy 1-3 retelling consistently treats the Kadesh period as a distinct era from the early wilderness, supporting the latter view.</p>",
        "3": "<p>The community's complaint inverts the logic of death: they wish they had died with their brothers before YHWH — a reference to the deaths of Korah's company and the 14,700 from the plague (ch16). Death in divine judgment is preferred to this prolonged uncertainty. The preference for a past death over the present struggle recurs as the most extreme form of wilderness despair; it was exactly this despair (Num 14:2) that generated the original forty-year sentence.</p>",
        "4": "<p>The accusation: Moses and Aaron have brought YHWH's congregation into the wilderness to die, along with their livestock. The phrase <em>qahal YHWH</em> — YHWH's congregation — appears in the complaint itself, a rhetorical move that uses covenant language against the covenant leaders. If this is YHWH's congregation, why are they dying in the wilderness? The argument picks up the same logic Moses used in his intercession (Num 14:13-16) — now turned against him.</p>",
        "5": "<p>The complaint catalogues agricultural abundance they have been denied: grain, figs, vines, pomegranates, water. The list maps precisely onto the promised-land abundance described by the scouts (Num 13:23,27), making the contrast pointed: the generation that refused the land now mourns the absence of the land's produce. The wilderness is experienced as privation only against the memory of what Egypt had and the promise of what Canaan offers.</p>",
        "6": "<p>Moses and Aaron's response — falling facedown before the assembly — is their standard crisis posture (Num 14:5; 16:4,22,45; 17:10). The glory of YHWH appears to them, providing divine direction. The sequence shows the pattern: communal crisis → intercessory prostration → divine appearance → solution. The leaders function as the conduit between the community's need and the divine response throughout the wilderness narratives.</p>",
        "7": "<p>YHWH speaks to Moses alone now — Aaron is not addressed, though he is present and complicit in what follows (v12 includes him in the sentence). The specific addressing of Moses may reflect the text's focus on Moses as the figure who will strike the rock, even though Aaron was addressed equally for the Rephidim crisis (Exod 17:5-6). The command is addressed where the action and failure will occur.</p>",
        "8": "<p>The command: take the staff, assemble the congregation, and <em>speak to the rock</em> (<em>wəḏibbartěm ʾel-hassela</em>). The explicit verb is <em>speak</em> — not strike. The staff is present (probably the staff associated with the snake miracle, Exod 7:15-20, or Aaron's budding rod from ch17) but is not the instrument of water-production; the word spoken to the rock is. This is YHWH's advance provision for the episode's theological test: the distinction between striking and speaking is established before Moses can ignore it.</p>",
        "9": "<p>Moses takes the staff from before YHWH — from its storage at the front of the testimony (cf. Aaron's rod, Num 17:10) or from its place before the ark. The staff's retrieval is authorized; the problem will not be possession of the staff but its use. The narrative pacing — take the staff, assemble the community, gather before the rock — creates a ceremonial buildup to what should be a spoken miracle.</p>",
        "10": "<p>Moses's words to the congregation: <em>šimʿû-nāʾ hammōrîm</em> — hear, you rebels! The word <strong>מֹרִים (mōrîm)</strong> — rebels — is a sharp address. The same root <em>mārâ</em> appears in v24: Aaron is excluded from the land because he and Moses rebelled against YHWH's mouth (<em>mərîtem ʾet-pî</em>). Moses's anger at the community's rebellion reflects the legitimate frustration of a forty-year leader; but his ensuing action indicates that something in his response is itself the problem. The nature of Moses's failure is disputed: some say pride (<em>shall we bring</em> water rather than YHWH?), some say unbelief, some say disobedience to the speaking-not-striking command.</p>",
        "11": "<p>Moses strikes the rock twice. The single-strike of Exod 17:6 becomes a double strike — whether from emphasis, doubt, or frustration, the text does not explain. Water pours out in abundance (<em>wayyēṣəʾû mayim rabbîm</em>). The miracle still occurs; YHWH provides water despite Moses's disobedience. This is significant: the provision does not vindicate the method. The grace that produces water simultaneously highlights the failure — the people receive what they need, but Moses has forfeited the land he has served toward for forty years.</p>",
        "12": "<p>The divine verdict: Moses and Aaron did not trust YHWH enough (<em>lōʾ-heʾĕmantěm bî</em>) to uphold his holiness (<em>ləhaqdîšênî</em>) before the Israelites. The failure is characterized as a failure of faith and a failure of sanctification — not primarily a failure of technique. Whatever Moses did or said, it communicated something about YHWH that diminished rather than displayed his glory. The consequence — neither shall bring the assembly into the promised land — is devastating precisely because it is proportional to their position: those who lead must embody what they proclaim.</p>",
        "13": "<p>The place name <em>Meribah</em> (from <em>rîḇ</em>, to contend, quarrel) recalls Massah-and-Meribah of Exod 17:7. The naming etiology: where Israel quarreled with YHWH (<em>rāḇû ʾet-YHWH</em>) and YHWH showed himself holy among them (<em>wayyiqqāḏēš bām</em>). The divine holiness was displayed through judgment on Moses rather than through Moses's action — a theological irony that runs through the narrative. The water of Meribah becomes a canonical symbol of both Israel's faithlessness (Ps 81:7; 95:8) and YHWH's continuing provision despite it.</p>",
        "14": "<p>Moses sends messengers to the king of Edom requesting passage through Edom's territory via the King's Highway. The fraternal language — <em>ʾāḥîkā yiśrāʾēl</em> — your brother Israel — invokes the Jacob-Esau relationship (Gen 25:23-26; 32-33). The request contains a brief historical summary of the exodus (vv14-16), essentially recounting YHWH's acts as grounds for Edomite solidarity. The appeal to shared ancestry reflects the political reality that Edom was a neighboring nation with a covenanted ethnic relationship to Israel, even if that relationship was fraught.</p>",
        "15": "<p>The summary of Egyptian slavery and the long sojourn (<em>wanneqen bəmiṣrayim yāmîm rabbîm</em> — we dwelled in Egypt for many days) frames Israel's history as one of prolonged suffering followed by divine rescue. The recitation of ancestral suffering as diplomatic credential appears in ancient Near Eastern treaty and petition contexts — shared hardship and divine rescue are framed as grounds for mutual respect and accommodation.</p>",
        "16": "<p>The crucial claim: YHWH heard our cry and sent a <em>malʾāk</em> — a messenger/angel — who brought us out of Egypt. The <em>malʾāk</em> here may refer to Moses himself (Exod 3:10; 7:1) or to the divine presence that accompanied the exodus (Exod 14:19). The Kadesh location (<em>ʾel-Qāḏēš</em>) is mentioned — they are speaking from the edge of Edom, at the place where forty years earlier they failed to enter the land; now they request the right of passage through their kinsman's territory.</p>",
        "17": "<p>The terms of the request: they will travel only the King's Highway (<em>ḏerek hammelek</em>), the main international road running north-south through Transjordan. They will not enter fields or vineyards, not drink well water without payment. The carefully limited request acknowledges Edomite sovereignty — Israel is asking for right of transit, not settlement. The King's Highway was the major ANE commercial artery; similar right-of-passage negotiations appear in Akkadian diplomatic correspondence.</p>",
        "18": "<p>Edom's flat refusal: <em>lōʾ taʿăḇōr bî</em> — you shall not pass through me. The use of first-person singular (<em>bî</em> — through me) is striking: Edom speaks as a single person representing the nation, mirroring Israel's address as <em>ʾāḥîkā yiśrāʾēl</em> — your brother Israel. The fraternal language that Israel used to appeal to solidarity, Edom uses to assert its independence as a separate national entity. The sword threat (<em>ḇeḥāreḇ ʾēṣēʾ liqrāʾtekā</em>) rejects diplomacy entirely.</p>",
        "19": "<p>Israel modifies its request: they will use only the main road (<em>bimsilā nemlek</em>), pay for any water consumed, and ask nothing else. The offer of payment for water — normally free or charged only for cistern access — represents a further accommodation. The escalation of accommodation signals genuine desire to avoid conflict with Edom, which the Torah elsewhere treats as protected from Israelite conquest (Deut 2:4-6: do not provoke Edom, for I have given Esau's descendants Mount Seir as their possession).</p>",
        "20": "<p>Edom's second refusal, this time with military display: a large and powerful army marching out. The use of force to deny passage prevents any diplomatic resolution. The absence of divine judgment against Edom here — despite the treatment of Israel — reflects the covenant theology articulated in Deut 2: Edom's land is not Israelite inheritance, and Edomite sovereignty over their own territory is respected within the covenant framework. The enmity surfaces later in Israelite history (2 Sam 8:14; 1 Kgs 11:14-22) and becomes a major prophetic theme (Obadiah; Isa 34; Jer 49:7-22).</p>",
        "21": "<p>Israel turns away from Edom rather than fight — a divinely sanctioned withdrawal consistent with Deut 2:4-8's prohibition on provoking Edom. The turning away is not weakness but obedience to the covenant framework governing Israel's relationship with Edom. The route around Edom (toward the Red Sea, 21:4) adds distance and hardship to the journey, contributing to the discouragement that leads to the next crisis (21:4-5).</p>",
        "22": "<p>From Kadesh to Mount Hor: a location on the border of Edom, traditionally identified (from early Byzantine sources) as Jebel Harun near Petra, though the exact location is uncertain. The movement toward the borders of Edom is geographically necessary for the route around it. Mount Hor's significance is entirely determined by what happens there: Aaron's death and the priestly succession.</p>",
        "23": "<p>At Mount Hor, YHWH addresses Moses and Aaron together — as they were addressed throughout Numbers — for the last time. The divine speech covers Aaron's impending death, the reason for it (v24: rebellion at Meribah), the succession procedure (vv25-26), and the location. The divine announcement of death to Aaron himself (as Moses receives his in Deut 32:49-50) frames death as a covenant appointment rather than a biological event.</p>",
        "24": "<p>Aaron will be gathered to his people (<em>yēʾāsep̄ ʾel-ʿammāyw</em>) — the standard euphemism for death in P (Gen 25:8,17; 35:29; 49:33). The reason stated: Aaron and Moses rebelled against YHWH's mouth at Meribah. <em>Mərîtem ʾet-pî YHWH</em> — you rebelled against my mouth — uses the word for speaking-against-divine-command that appears throughout the wilderness narratives. Aaron's exclusion from the land is the same as Moses's (v12) — they stand and fall together as the dual leadership of the founding generation.</p>",
        "25": "<p>The priestly succession ceremony involves Moses, Aaron, and Eleazar ascending together. The public nature of the ascent — in sight of the whole community (v27) — makes the transfer of priestly authority a witnessed act. Eleazar's installation as chief priest is not a private arrangement but a national event. The sequence parallels Moses's public blessing of Joshua before the assembly (Deut 31:7-8,14-23; Num 27:18-23), establishing the principle that covenant leadership succession is communal, not dynastic.</p>",
        "26": "<p>Moses removes Aaron's vestments (<em>bigdê hakkōhēn</em>) and transfers them to Eleazar. The priestly vestments — described in Exod 28-29 as the instruments of Aaron's consecration and ongoing priestly identity — are the visible marks of office. Transferring them while Aaron is still alive rather than after his death preserves the continuity of the office and ensures Eleazar is fully clothed in priestly authority before Aaron dies. The vestments are invested with the office; they do not die with the officeholder.</p>",
        "27": "<p>Moses does exactly as YHWH commanded — the compliance formula appears here as it does after each major divine instruction, emphasizing that the priestly succession is a divine act carried out through human obedience. The whole community watches from below; the three men — Moses (prophet), Aaron (high priest), Eleazar (priest-to-be) — on the mountain represent the whole covenant structure in miniature.</p>",
        "28": "<p>Aaron dies there on the mountaintop, his vestments now on Eleazar. The stripping of Aaron's vestments and his death immediately after form a liturgy of departure: he is divested of his office, then dies. The mountain setting (like Moses's death on Nebo, Deut 34) frames these deaths as sovereign divine moments — not battlefields or sickbeds but divine appointment mountains. Moses and Eleazar come down, Aaron remains on the mountain.</p>",
        "29": "<p>When the community learns Aaron has died, all the house of Israel mourns thirty days (<em>šelōšîm yôm</em>). Thirty days of mourning is also prescribed for Moses's death (Deut 34:8) — the maximum mourning period in Israelite custom, reserved for the most significant figures. Aaron's mourning is for the entire community (<em>kol-bêt yiśrāʾēl</em>), reflecting his role as the high priest of the whole people rather than a tribal or family leader. The institution of corporate mourning for a single figure marks the covenant community's shared stake in its leaders' lives and deaths.</p>"
    },
    "21": {
        "1": "<p>The king of Arad (a Canaanite city in the Negev) attacks Israel as it approaches from the direction of Atharim — possibly a road or pass rather than a place name. The attack catches Israel in an exposed military position. The name Arad is connected with a site in the Negev later settled by Judah (Judg 1:16-17); this episode may reflect pre-conquest contact that later became an administrative boundary. The unprovoked Canaanite aggression (Israel was not trying to enter Canaan from this direction) frames what follows as defensive war.</p>",
        "2": "<p>Israel makes a <em>vow to YHWH</em> (<em>neder laYHWH</em>) invoking the holy-war formula: if YHWH delivers the enemy, Israel will devote the Canaanite cities to complete destruction (<em>ḥērem</em>). The vow structure here is identical to the vow-law of ch30: a binding commitment to YHWH as the condition of receiving divine assistance. The ḥērem vow appears in Deuteronomy 7 and 20 as the standard prescription for Canaanite cities; here Israel voluntarily adopts the ḥērem obligation as a request rather than receiving it as a command.</p>",
        "3": "<p>YHWH responds to the vow — <em>wayyišmaʿ YHWH bəqôl yiśrāʾēl</em> — the same hearing formula as YHWH hearing Israel's cry in Egypt. The Canaanites and their cities are devoted to destruction (<em>wayyaḥărēm ʾotām wəʾet-ʿārêhem</em>). The place is renamed Hormah — from <em>ḥerem</em> (devoted destruction) — a name appearing earlier as the site of Israel's defeat (14:45), now transforming into a victory marker. The geography reverses: the place of punishment becomes the place of vindication.</p>",
        "4": "<p>The route around Edom creates a dispiriting detour — the opposite direction from the land. The wilderness road by the Red Sea (<em>ḏerek yam-sûp̄</em>) through Edom's border is recognized here as geographically discouraging; they traveled away from the destination to avoid military confrontation with Edom (which YHWH had forbidden). The text preserves the existing verse; the summary context is: the detour generated the impatience (<em>qāṣar nep̄eš hāʿām</em> — the people's soul was shortened/discouraged) that became the next complaint.</p>",
        "5": "<p>The complaint combines theological (against God) and political (against Moses) opposition, unique in combining both objects of the complaint in one verse. The bread (<em>leḥem</em>) is called worthless (<em>qəlōqēl</em> — contemptible, nauseous) — a word used only here in the Torah. This insults the manna that YHWH provided; it is not merely complaining about lack but expressing contempt for what has been given. The complaint about the manna being disgusting provokes a different divine response than previous water-and-food complaints — the serpents rather than a plague or earthquake.</p>",
        "6": "<p>YHWH sends <em>hanneḥāšîm haśśərāp̄îm</em> — the burning/fiery serpents. <strong>שָׂרָף (śārāp̄)</strong> means burning or fiery, possibly describing the burning sensation of the venom, the appearance of the snakes, or both. The same word <em>śərāp̄îm</em> describes the heavenly beings in Isa 6:2 — six-winged creatures before YHWH's throne — suggesting a root meaning of glowing/burning intensity. Many Israelites die from the bites. The divine sending of serpents as judgment echoes the Eden narrative (Gen 3) and anticipates the resolution through a bronze serpent mounted on a pole.</p>",
        "7": "<p>The people confess: <em>ḥāṭāʾnû kî-ḏibbarnû ḇaYHWH ûḇekā</em> — we have sinned by speaking against YHWH and against you. The confession is specific — they name the exact sin (speaking against). Moses intercedes for them; YHWH's response does not remove the serpents but provides a healing mechanism, maintaining the judgment while opening a path of restoration. The pattern — sin, judgment, confession, provision of remedy — mirrors the Korah crisis structure but produces a different type of resolution.</p>",
        "8": "<p>YHWH instructs Moses to make a <em>śārāp̄</em> — a fiery/serpent image — and mount it on a pole (<em>nēs</em>). Anyone who was bitten and looked at it would live (<em>wāḥāy</em>). The image of the snake that heals from snake-bites concentrates the serpent's danger and transforms it into healing; the form of judgment becomes the instrument of restoration. This structural reversal — the symbol of the curse becomes the cure — became foundational for Christological typology: the Christ who bore sin's curse becomes the healing for sin (John 3:14-15; 2 Cor 5:21).</p>",
        "9": "<p>Moses makes a bronze serpent (<em>neḥaš nəḥōšet</em>) — a pun in Hebrew: the word for snake (<em>nāḥāš</em>) and bronze (<em>nəḥōšet</em>) share the same root consonants, creating an auditory connection between the material and the object. The bronze serpent was later preserved in the Jerusalem temple, where it was worshipped as a cultic object called <em>Nəḥuštān</em> (2 Kgs 18:4). King Hezekiah destroyed it as part of his religious reforms — an interesting trajectory: a legitimate healing instrument became an object of illegitimate worship.</p>",
        "10": "<p>The wilderness itinerary resumes after the bronze serpent episode. The movement from Oboth toward the plains of Moab marks the final phase of the wilderness journey, transitioning from the post-Sinai law-giving and crisis period to the pre-conquest encampment east of the Jordan. Each station in the itinerary of vv10-20 represents the last legs of Israel's forty-year journey, with conquest imminent.</p>",
        "11": "<p>Iye-abarim in the wilderness facing Moab from the east — <em>ʿal p̄ənê môʾāḇ mimizraḥ haššāmeš</em>. The location places Israel in the Transjordanian wilderness east of Moab, moving northward along the Moabite border. The text preserves several station names unidentifiable in modern geography, reflecting authentic ancient itinerary records rather than composed theological geography.</p>",
        "12": "<p>The valley of Zered (<em>naḥal zāred</em>) is the major wadi marking the boundary between Edom and Moab (Deut 2:13-14 makes this crossing the significant marker of the completion of the forty years of wilderness wandering, as the last of the condemned generation has died by this point). The crossing of the Zered is thus structurally significant: it marks the generational transition from judgment to conquest.</p>",
        "13": "<p>The Arnon (<em>naḥal ʾArnôn</em>) was the major boundary river between Moab and the Amorite territory north of it. Israel encamps on the far (north) side of the Arnon, in the wilderness between Moab and the Amorites. This geographical precision sets up the diplomatic exchange with Sihon: Israel is in territory that Sihon controls, not Moab — so Moab's permission is not at issue for the next stage of the journey.</p>",
        "14": "<p>The <strong>Book of the Wars of YHWH</strong> (<em>sep̄er milḥāmōt YHWH</em>) — an ancient Israelite poetic anthology no longer extant, quoted here as a geographical authority. The existence of such a text, predating the final composition of Numbers, demonstrates that Numbers drew on older oral and written sources. Several scholars connect this book to the Song of Deborah (Judg 5) and other early Israelite war poetry preserved in fragments. The quotation here establishes Waheb in Suphah and the Arnon as recognized geographical markers from Israel's oldest literary traditions.</p>",
        "15": "<p>The continuation of the quotation locates the Arnon's slope leading to the settlement of Ar, resting on Moab's border. Ar was Moab's major city (Num 21:28; Isa 15:1; Deut 2:9). The ancient poetry functions as a geographical and historical marker — the Arnon as the acknowledged boundary — providing independent pre-narrative attestation of the territorial claims that follow in the Sihon and Og narratives.</p>",
        "16": "<p>Beer — <em>bəʾēr</em> — means simply Well. YHWH promises water here: <em>ʾăsop̄â hāʿām wəʾetnâ lāhem māyim</em> — assemble the people and I will give them water. This provision-from-the-well appears after the bronze serpent episode, possibly as an implicit contrast: where judgment-and-healing marked the serpent episode, here provision is straightforward. The well at Beer becomes the occasion for one of the oldest preserved songs in the Hebrew Bible.</p>",
        "17": "<p>The Song of the Well (vv17-18): <em>ʿălî bəʾēr</em> — spring up, O well — Israel's liturgical response to the gift of water. This is one of the most ancient poetic fragments preserved in Numbers, possibly from the same source tradition as the Book of the Wars of YHWH. The song addresses the well directly — a personification of the life-giving water that has been the subject of complaint and crisis throughout the wilderness narratives. Here, at the edge of the promised land, the well is cause for celebration rather than contention.</p>",
        "18": "<p>The princes (<em>śārîm</em>) dug the well with the scepter (<em>məḥōqēq</em>), nobles of the people with their own staffs (<em>bəmiśʿenōtām</em>). The imagery of leaders digging with ceremonial staffs may reflect the ANE practice of royal water-right ceremonies, where royalty formally inaugurated wells or irrigation projects. The well at Beer stands as a symbol of leadership provision at the threshold of the conquest — what princes provide in contrast to the murmuring people's self-provision.</p>",
        "19": "<p>The itinerary continues from Beer through Mattanah (<em>gift</em>), Nahaliel (<em>wadi of God</em>), and Bamoth (<em>high places</em>) — three station names that may have geographical significance (Nahaliel as a wadi, Bamoth as high-place sites) or may be symbolic of the ascent toward the heights of Moab and the Pisgah range from which the land will be surveyed.</p>",
        "20": "<p>Bamoth to the valley in Moab where Pisgah (<em>hap̄isgāh</em>) overlooks the wasteland (<em>yāšîmōn</em>). Pisgah is the mountain from which Balaam will bless Israel in ch23-24 and from which Moses will survey the promised land before his death (Deut 34:1 — the peak of Pisgah, identified with Nebo). The itinerary arrives at the geographical staging point for the rest of Numbers: the plains of Moab opposite Jericho, from which the conquest will be organized.</p>",
        "21": "<p>The diplomatic formula with Sihon king of the Amorites mirrors the Edom negotiation (20:14-17) almost exactly: messengers, request for passage on the King's Highway, promise not to enter fields or vineyards or drink well water. The parallel structure invites comparison: Edom's refusal was respected (Deut 2:4-6), while Sihon's refusal triggers military conflict. The difference: Edom is a brother nation protected from conquest by covenant; Sihon is an Amorite king whose land Israel was divinely destined to inherit.</p>",
        "22": "<p>The same terms as the Edom request: the King's Highway only, no agricultural encroachment, no water taken without payment. The repetition of the same diplomatic language shows that Israel approached Sihon in the same good faith as Edom. Deuteronomy 2:30 adds that YHWH hardened Sihon's spirit specifically to give Israel grounds to attack — making Sihon's refusal divinely determined within the conquest framework, as Pharaoh's hardening was within the exodus framework.</p>",
        "23": "<p>Sihon refuses passage and marches his forces into the wilderness to meet Israel at Jahaz. The refusal is identical in structure to Edom's (v18,20) but leads to a completely different outcome — not because Israel chose differently but because the conquest mandate applied to Amorite territory. Israel strikes Sihon's forces and takes possession of Amorite land from the Arnon to the Jabbok. The vocabulary (<em>wayyiḵbōš</em> — he took possession) introduces the conquest-language that dominates the rest of Numbers and all of Joshua.</p>",
        "24": "<p>Israel's northern boundary after Sihon's defeat: the Jabbok (<em>naḥal yabbōq</em>) — the river where Jacob wrestled with God (Gen 32:22), now the boundary of Israelite territory. The southern boundary is the Arnon, the northern boundary is the Jabbok (and the Ammonite border beyond). The phrase <em>kî ʿazzûz gəḇûl bənê ʿammôn</em> — for the border of the Ammonites was strong — explains why Israel stopped: Ammon was protected from conquest by the same covenant principle as Edom and Moab (Deut 2:19-23).</p>",
        "25": "<p>Israel settles in the Amorite towns, including Heshbon (<em>ḥešbôn</em>) and all its surrounding settlements. Heshbon becomes the royal capital of Israel's Transjordanian territory. The settlement of Amorite towns — rather than destruction — establishes the Transjordanian tribes' inheritance east of the Jordan, elaborated in Num 32 where Reuben, Gad, and half of Manasseh formally claim this territory.</p>",
        "26": "<p>Heshbon was Sihon's royal city; Sihon had previously taken it from the former Moabite king. The note that Sihon had conquered Moab is significant: Israel is not taking Moab's territory but Sihon's Amorite conquest territory. Deuteronomy 2:9 prohibits Israel from taking Moabite land; the clarification here explains why the conquest of Heshbon does not violate that prohibition. The legal-historical precision of the parenthetical note reflects P's concern for the legitimacy of territorial claims.</p>",
        "27": "<p>The taunt-song (<em>hamoššəlîm</em> — the poets/those who use proverbs) celebrates Sihon's original conquest of Moab: come to Heshbon, let Sihon's city be rebuilt. The quoted poetry is pre-Israelite — a Moabite lament for their own defeat by Sihon, which Israel now appropriates to mock Sihon. The use of enemy's own war poetry as the celebration of conquest represents a sophisticated literary and political appropriation of earlier cultural material.</p>",
        "28": "<p>The taunt-song imagery: fire coming out of Heshbon, a flame from Sihon's city devouring Ar of Moab. The fire/flame imagery describes Sihon's earlier conquest of Moab; now that same city is in Israelite hands, and the fire that once consumed Moab's defeat is itself consumed. The poetic justice is structural: Sihon's conquering fire is itself extinguished by a stronger force.</p>",
        "29": "<p>Woe to Moab — the taunt mourns the people of Chemosh (<em>ʿam kəmôš</em>). Chemosh was the national deity of Moab (1 Kgs 11:7,33; 2 Kgs 23:13); the reference uses the Moabite theological framework (their god failed to protect them from Sihon) against them. The phrase <em>wayyittēn bānāyw p̄ēliṭim ûbənōtāyw baššibî</em> — he gave his sons as fugitives and his daughters into captivity — describes Chemosh as having abandoned his people, a common ANE formulaic expression for a defeated nation's god.</p>",
        "30": "<p>Israel's own victory song supplements the Moabite taunt: we have devastated Heshbon as far as Dibon, destroyed as far as Nophah and Medeba. The geographical extent of destruction runs through Moabite-Sihonite territory. The quotation of multiple ancient poetry sources (Book of Wars, Moabite taunt-song, Israelite victory-song) within a single narrative unit gives the Sihon-Og conquest section exceptional literary density, marking it as a canonical high point in the wilderness narrative.</p>",
        "31": "<p>Israel settles in the land of the Amorites — the formal statement of possession that prepares for the Numbers 32 distribution narrative. The settlement precedes the Jordan crossing; the Transjordanian territory becomes a satellite of the conquest, an eastern wing of the promised land whose legitimacy depends on the Sihon victory narrated here and whose full history extends through the period of the Judges.</p>",
        "32": "<p>Jazer — a city in the Amorite territory north of Heshbon — is scouted and captured along with its surrounding settlements. The systematic expansion from Heshbon northward reflects the methodical nature of the Transjordanian campaign. Jazer later becomes a significant Gadite town (Num 32:1,3,35) and appears in the Levitical city lists (Josh 21:39).</p>",
        "33": "<p>Og king of Bashan comes out against Israel at Edrei. Bashan was the northern Transjordanian region, later notable for its rich agricultural land (oak forests, cattle; Ps 22:12; Amos 4:1). Og is repeatedly described as the last of the Rephaim — a giant or pre-Israelite race (Deut 3:11 mentions his oversized iron bed). The encounter with Og follows immediately on Sihon's defeat, giving the impression of rapid sequential conquest of the entire Transjordanian corridor.</p>",
        "34": "<p>YHWH's direct encouragement to Moses: <em>ʾal-tîrāʾ ʾōtô</em> — do not fear him. The fear-not formula appears throughout the conquest narratives (Josh 8:1; 10:8; 11:6) as the divine guarantee preceding battle. The formula <em>kî bəyāḏekā nātatî ʾōtô</em> — I have given him into your hand — declares the victory as accomplished before the battle. Doing exactly to Og what was done to Sihon is the divine mandate: the two kings are juridically equivalent, and their defeat together constitutes the complete pacification of Transjordan before the Jordan crossing.</p>",
        "35": "<p>The complete destruction of Og, his sons, and his whole army — leaving no survivors (<em>wəlōʾ-šiʾēr lô śārîḏ</em>) — completes the Transjordanian conquest. The phrase echoes throughout the conquest narratives in Joshua (Josh 8:22; 10:28,30,33,37,39; 11:8); the destruction formula becomes the literary marker of complete holy-war victory. Israel takes possession of Og's land, completing the territorial base from which the Jordan crossing and the Cisjordanian conquest will proceed. The two victory narratives (Sihon and Og) are quoted repeatedly in Deuteronomy-Psalms as paradigm events establishing YHWH's power for the conquest.</p>"
    }
}

def main():
    data = load_comm('mkt-context', 'numbers')
    merge_comm(data, NUMBERS)
    save_comm('mkt-context', 'numbers', data)

main()
